INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('f1cd25a9-5ec3-4538-9ed2-d5a6ff098879', '89904b2b-403b-4604-9a47-fb0e324fcc85', 'Pull out my phone and fact-check it in real time, mid-conversation', 6, '{label-reader,over-thinker}', 3, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('a4137928-48ea-4fae-8251-4e1ed9cece62', '43c81c7e-541f-4241-bc1e-1da108d05d6e', 'Suggestions, not rules. It smells fine, it IS fine.', 0, '{impulse-eater,risk-taker}', 0, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('6d8f557d-eca6-4fbf-b262-65a931808402', '43c81c7e-541f-4241-bc1e-1da108d05d6e', 'I notice them but I''m not obsessed. A day or two is fine.', 2, '{convenience-first,creature-of-habit}', 1, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('2e907edd-cceb-42a5-a0f2-9a198a2facb4', '43c81c7e-541f-4241-bc1e-1da108d05d6e', 'I respect the date and toss anything past it', 4, '{mindful-eater,label-reader}', 2, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('ba15117d-1ef3-4eed-84d6-2be12418495f', '43c81c7e-541f-4241-bc1e-1da108d05d6e', 'I track best-by dates in a spreadsheet. Don''t @ me.', 7, '{label-reader,over-thinker}', 3, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('3ec2ebcd-b6cd-4003-a355-251cc3b10e57', 'd8e95414-16eb-400c-bfc7-0fb78e1ba514', 'Ingredient lists? On food? Wild concept.', 0, '{impulse-eater,blissfully-unaware}', 0, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('ee87d36b-6bd9-484a-8d84-1a28bb80464b', 'd8e95414-16eb-400c-bfc7-0fb78e1ba514', 'I glance if I remember, but mostly I trust the packaging vibes', 2, '{convenience-first,blissfully-unaware}', 1, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('5f190eca-77c5-4621-86ba-7e2894bf98d6', 'd8e95414-16eb-400c-bfc7-0fb78e1ba514', 'I skim for the big ones — sugar, sodium, anything I can''t pronounce', 5, '{mindful-eater,label-reader}', 2, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('5cdaf67e-9780-4195-acfd-230ba172c986', 'd8e95414-16eb-400c-bfc7-0fb78e1ba514', 'I read every word and Google anything over three syllables', 7, '{label-reader,over-thinker}', 3, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.option (id, question_id, text, score, tags, "position", created_at, updated_at) VALUES ('a82d46ee-b38d-4279-947b-b75c45c4f6d7', 'e70eb9f4-6b16-4954-945b-e39c843221ed', 'Whatever''s fastest — cereal, crackers, maybe some cheese', 0, '{impulse-eater,convenience-first}', 0, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
