INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('6639ca26-6539-4a8b-8ab8-16975bec5744', 'e6796901-6aca-4291-bcab-efcc188bc584', 'The Blissfully Unaware', 'Food is fuel and vibes, and honestly? You''re thriving. You eat with joy, zero spreadsheets, and a breezy confidence that the sniff test never lies. Life''s too short to read the back of a chip bag.', 'See how Olive can help (gently)', 'https://oliveapp.com/', 0, 10, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('d6e307c0-2fe5-4351-beee-2e54226ccbee', 'e6796901-6aca-4291-bcab-efcc188bc584', 'The Casual Grazer', 'You''re not totally in the dark — you''ve heard of fiber — but you''re not losing sleep over ingredient lists either. You eat what works, trust your gut (literally), and Google things occasionally when the mood strikes.', 'Level up your food game', 'https://oliveapp.com/#features', 11, 18, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('a669f353-891e-4bf9-adf8-8534c8a14653', 'e6796901-6aca-4291-bcab-efcc188bc584', 'The Mindful Muncher', 'You read labels. Sometimes. You''re the person who orders something healthy and then steals fries off someone else''s plate — balance! You care about what goes in, but you''re not about to ruin a good meal over it.', 'Meet your perfect food tool', 'https://oliveapp.com/#features', 19, 25, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('cc62f909-3688-4124-80b8-d559b465c1d2', 'e6796901-6aca-4291-bcab-efcc188bc584', 'The Label Detective', 'Congratulations — you have read more nutrition panels than most people have read books. You know what maltodextrin is, you''ve side-eyed a ''natural flavors'' disclosure, and you take the long route through the grocery store on principle. We respect it deeply.', 'You''ll love Olive. Seriously.', 'https://oliveapp.com/', 26, 33, '2026-04-28 18:59:28.451725+00', '2026-04-28 18:59:28.451725+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('c4659ac4-7787-4f81-996b-903528165da1', '3a3322db-1dcd-4ce7-bfff-f9f126727be2', 'You''re Living on Ultra-Processed Everything 🚨', 'Your diet is heavily reliant on packaged, processed, and fast food. The good news? Small swaps can make a huge difference — and Olive is built to help you find them fast.', 'Try Olive Free', 'https://oliveapp.com/', 0, 10, '2026-04-28 19:00:13.106533+00', '2026-04-28 19:00:13.106533+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('b6b2b9a9-8595-4a2c-ad85-4288a027f6b7', '3a3322db-1dcd-4ce7-bfff-f9f126727be2', 'Ultra-Processed Food Is Definitely Creeping In 🤔', 'You''re not in the deep end, but processed food is a regular part of your routine. Olive can help you spot the sneaky ingredients and find better alternatives without overhauling your whole life.', 'See How Olive Can Help', 'https://oliveapp.com/#features', 11, 18, '2026-04-28 19:00:13.106533+00', '2026-04-28 19:00:13.106533+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('9bd7cea4-0404-4b0a-b9f1-bd7599860600', '3a3322db-1dcd-4ce7-bfff-f9f126727be2', 'You''re Doing Pretty Well — With Room to Grow 🌱', 'You make decent choices most of the time, but there''s still some processed food in the mix. Olive can sharpen your label-reading skills and help you level up the last few habits.', 'Check Out Olive', 'https://oliveapp.com/#features', 19, 26, '2026-04-28 19:00:13.106533+00', '2026-04-28 19:00:13.106533+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('a332e8ac-bd42-4eaf-8737-a0d92c394d13', '3a3322db-1dcd-4ce7-bfff-f9f126727be2', 'You''re a Whole-Food Hero 🥦', 'Your diet is impressively low in ultra-processed food — you cook, you read labels, and you snack smart. Olive is here whenever you want to go even deeper on ingredient transparency.', 'Explore Olive', 'https://oliveapp.com/', 27, 30, '2026-04-28 19:00:13.106533+00', '2026-04-28 19:00:13.106533+00');
